import { useState, useEffect } from "react";
import './Payment.css';

const AmountForm = ({ amount = 0, transportData, onError, onSuccess }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    if (amount && amount > 0) {
      handleSubmit(amount);
    }
  }, [amount]);

  const handleSubmit = async (submitAmount) => {
    setIsLoading(true);
    setError("");

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        setError("Authentication required");
        setIsLoading(false);
        return;
      }

      const amountInPaise = Math.round(submitAmount * 100);

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: amountInPaise,
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      const data = await response.json();
      
      if (data.success) {
        const form = document.createElement('form');
        form.method = 'POST';
        form.action = data.data.APIURL;
        form.target = '_blank';
        
        Object.entries(data.data).forEach(([key, value]) => {
          if (key !== 'APIURL' && value) {
            const input = document.createElement('input');
            input.type = 'hidden';
            input.name = key.toUpperCase();
            input.value = value;
            form.appendChild(input);
          }
        });
        
        document.body.appendChild(form);
        form.submit();
        document.body.removeChild(form);
        
        if (onSuccess) onSuccess();
      } else {
        setError(data.message || "Payment failed");
        if (onError) onError(data.message);
      }
    } catch (err) {
      setError("Network error");
      if (onError) onError("Network error");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="amount-form-container">
      {isLoading && (
        <div className="loading-indicator">
          <div className="spinner"></div>
          <p>Processing payment...</p>
        </div>
      )}

      {error && (
        <div className="error-message">
          <p><strong>Error:</strong> {error}</p>
          <button onClick={() => {
            setError("");
            if (onError) onError();
          }}>
            Use COD Instead
          </button>
        </div>
      )}
    </div>
  );
};

export default AmountForm;
